import React, { useState } from "react";
import { ethers } from "ethers";
import VoiceItABI from "./VoiceIt.json";

const CONTRACT_ADDRESS = "0x5FbDB2315678afecb367f032d93F642f64180aa3";

function App() {
  const [report, setReport] = useState("");
  const [loading, setLoading] = useState(false);
  const [success, setSuccess] = useState(false);
  const [error, setError] = useState(null);

  async function sendReport() {
    if (!window.ethereum) {
      setError("Please install MetaMask!");
      return;
    }

    if (!report.trim()) {
      setError("Please enter a report before submitting.");
      return;
    }

    setLoading(true);
    setError(null);

    try {
      const provider = new ethers.BrowserProvider(window.ethereum);
      const signer = await provider.getSigner();

      const contract = new ethers.Contract(
        CONTRACT_ADDRESS,
        VoiceItABI.abi,
        signer,
      );

      const tx = await contract.submitReport(report);
      await tx.wait();

      setSuccess(true);
      setReport("");
      setTimeout(() => setSuccess(false), 3000);
    } catch (err) {
      console.error("Submission failed:", err);
      setError(err.message || "Failed to submit report. Please try again.");
    } finally {
      setLoading(false);
    }
  }

  const styles = {
    container: {
      minHeight: "100vh",
      display: "flex",
      flexDirection: "column",
      alignItems: "center",
      justifyContent: "center",
      padding: "20px",
      backgroundImage:
        "radial-gradient(circle at 20% 50%, rgba(59, 130, 246, 0.1) 0%, transparent 50%), radial-gradient(circle at 80% 80%, rgba(139, 92, 246, 0.1) 0%, transparent 50%)",
    },
    card: {
      width: "100%",
      maxWidth: "500px",
      background: "rgba(15, 23, 42, 0.8)",
      backdropFilter: "blur(10px)",
      backgroundColor: "rgba(30, 41, 59, 0.6)",
      border: "1px solid rgba(148, 163, 184, 0.2)",
      borderRadius: "20px",
      padding: "40px 30px",
      boxShadow:
        "0 8px 32px 0 rgba(31, 38, 135, 0.25), inset 0 1px 0 rgba(255, 255, 255, 0.1)",
      transition: "all 0.3s ease",
    },
    header: {
      textAlign: "center",
      marginBottom: "32px",
    },
    title: {
      fontSize: "28px",
      fontWeight: "700",
      marginBottom: "8px",
      background: "linear-gradient(135deg, #60a5fa 0%, #a78bfa 100%)",
      WebkitBackgroundClip: "text",
      WebkitTextFillColor: "transparent",
      backgroundClip: "text",
      fontFamily: "'Space Mono', monospace",
      letterSpacing: "-0.5px",
    },
    subtitle: {
      fontSize: "14px",
      color: "#94a3b8",
      fontWeight: "400",
      lineHeight: "1.5",
    },
    inputWrapper: {
      marginBottom: "20px",
    },
    label: {
      display: "block",
      fontSize: "13px",
      fontWeight: "600",
      color: "#cbd5e1",
      marginBottom: "8px",
      textTransform: "uppercase",
      letterSpacing: "0.5px",
    },
    input: {
      width: "100%",
      padding: "14px 16px",
      fontSize: "14px",
      border: "1px solid rgba(148, 163, 184, 0.3)",
      borderRadius: "12px",
      background: "rgba(15, 23, 42, 0.5)",
      color: "#e2e8f0",
      fontFamily: "inherit",
      transition: "all 0.3s ease",
      outline: "none",
      backdropFilter: "blur(10px)",
      resize: "vertical",
      minHeight: "120px",
    },
    inputFocus: {
      borderColor: "rgba(96, 165, 250, 0.5)",
      background: "rgba(15, 23, 42, 0.7)",
      boxShadow: "0 0 0 3px rgba(96, 165, 250, 0.1)",
    },
    button: {
      width: "100%",
      padding: "14px 24px",
      fontSize: "15px",
      fontWeight: "600",
      border: "none",
      borderRadius: "12px",
      background: "linear-gradient(135deg, #3b82f6 0%, #8b5cf6 100%)",
      color: "#fff",
      cursor: "pointer",
      transition: "all 0.3s ease",
      textTransform: "uppercase",
      letterSpacing: "0.5px",
      boxShadow: "0 4px 15px rgba(59, 130, 246, 0.4)",
    },
    buttonDisabled: {
      opacity: "0.6",
      cursor: "not-allowed",
    },
    messageBox: {
      marginTop: "20px",
      padding: "12px 16px",
      borderRadius: "12px",
      fontSize: "13px",
      fontWeight: "500",
      border: "1px solid",
      animation: "slideIn 0.3s ease",
      backdropFilter: "blur(10px)",
    },
    successMessage: {
      backgroundColor: "rgba(34, 197, 94, 0.1)",
      borderColor: "rgba(34, 197, 94, 0.3)",
      color: "#86efac",
    },
    errorMessage: {
      backgroundColor: "rgba(239, 68, 68, 0.1)",
      borderColor: "rgba(239, 68, 68, 0.3)",
      color: "#fca5a5",
    },
  };

  return (
    <>
      <style>
        {`
          @media (max-width: 640px) {
            input, button {
              font-size: 16px;
            }
          }

          @keyframes slideIn {
            from {
              opacity: 0;
              transform: translateY(-10px);
            }
            to {
              opacity: 1;
              transform: translateY(0);
            }
          }

          input:focus {
            border-color: rgba(96, 165, 250, 0.5);
            background-color: rgba(15, 23, 42, 0.7);
            box-shadow: 0 0 0 3px rgba(96, 165, 250, 0.1);
          }

          button:hover:not(:disabled) {
            transform: translateY(-2px);
            box-shadow: 0 8px 20px rgba(59, 130, 246, 0.5);
          }

          button:active:not(:disabled) {
            transform: translateY(0);
          }
        `}
      </style>
      <div style={styles.container}>
        <div style={styles.card}>
          <div style={styles.header}>
            <h1 style={styles.title}>VoiceIt</h1>
            <p style={styles.subtitle}>
              Submit your report securely and anonymously to the blockchain
            </p>
          </div>

          <div style={styles.inputWrapper}>
            <label style={styles.label}>Your Report</label>
            <textarea
              style={styles.input}
              value={report}
              onChange={(e) => setReport(e.target.value)}
              placeholder="Share your story, report, or concern..."
              disabled={loading}
            />
          </div>

          <button
            style={{
              ...styles.button,
              ...(loading && styles.buttonDisabled),
            }}
            onClick={sendReport}
            disabled={loading}
          >
            {loading ? "Submitting..." : "Send to Blockchain"}
          </button>

          {success && (
            <div style={{ ...styles.messageBox, ...styles.successMessage }}>
              ✓ Report successfully stored on the blockchain!
            </div>
          )}

          {error && (
            <div style={{ ...styles.messageBox, ...styles.errorMessage }}>
              ✗ {error}
            </div>
          )}
        </div>
      </div>
    </>
  );
}

export default App;
